import { useState } from "react";
import { useParams, useSearchParams, useNavigate } from "react-router-dom";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { format } from "date-fns";
import { toast } from "sonner";
import { ArrowLeft, AlertCircle, AlertTriangle, CheckCircle, XCircle } from "lucide-react";

import { workScheduleService } from "@/api/workScheduleService";
import { HarmonyFullCalendar } from "@/components/ui/harmony-full-calendar";
import { WorkScheduleMonthList } from "@/features/work-schedule/components/WorkScheduleMonthList";
import { useUserWorkScheduleMonths } from "@/features/work-schedule/hooks/useWorkScheduleMonths";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { Button } from "@/shadcn/components/ui/button";
import { Badge } from "@/shadcn/components/ui/badge";
import { SCHEDULE_STATUS } from "@/features/work-schedule/constants";
import { WorkScheduleStatus } from "@/types/enums";
import { useAuth } from "@/shared/AuthContext";
import { PERMISSIONS } from "@/constants/permissions";
import { queryKeys } from '@/lib/queryKeys';
import { ROUTES } from '@/lib/routes';
import { getApiErrorMessage } from "@/api/app/apiError";
import type { WorkScheduleMonthSummary } from "@/types/dto";

function UserScheduleCalendar({ userId, year, month }: { userId: string; year: number; month: number }) {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { hasPermission } = useAuth();
  const canApprove = hasPermission(PERMISSIONS.WorkSchedule.Approve);

  const [rejectNotes, setRejectNotes] = useState("");
  const [isRejectOpen, setIsRejectOpen] = useState(false);
  const [isUnfreezeOpen, setIsUnfreezeOpen] = useState(false);

  const { data: schedule, isLoading, isError } = useQuery({
    queryKey: queryKeys.workSchedule.userSchedule(userId, year, month),
    queryFn: () => workScheduleService.getUserMonth(userId, year, month),
    enabled: !!userId && !!year && !!month,
    retry: false,
  });

  const invalidate = () => {
    queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.userSchedule(userId, year, month) });
    queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.pendingApproval() });
    queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.monthsUser(userId) });
  };

  const approveMutation = useMutation({
    mutationFn: (monthId: string) => workScheduleService.approveSchedule(monthId),
    onSuccess: () => { invalidate(); toast.success("Schedule approved."); },
    onError: (err) => toast.error(getApiErrorMessage(err)),
  });

  const rejectMutation = useMutation({
    mutationFn: ({ monthId, notes }: { monthId: string; notes: string }) =>
      workScheduleService.rejectSchedule(monthId, notes),
    onSuccess: () => { invalidate(); setIsRejectOpen(false); setRejectNotes(""); toast.success("Schedule rejected."); },
    onError: (err) => toast.error(getApiErrorMessage(err)),
  });

  const unfreezeMutation = useMutation({
    mutationFn: (monthId: string) => workScheduleService.unfreezeSchedule(monthId),
    onSuccess: () => { invalidate(); setIsUnfreezeOpen(false); toast.success("Schedule unfrozen."); },
    onError: (err) => toast.error(getApiErrorMessage(err)),
  });

  const monthLabel = format(new Date(year, month - 1, 1), "MMMM yyyy");
  const statusKey = schedule?.status as WorkScheduleStatus | undefined;
  const statusCfg = statusKey ? SCHEDULE_STATUS[statusKey] : undefined;

  const approvalActions = canApprove && schedule ? (
    <div className="flex items-center gap-2">
      {statusCfg && (
        <Badge variant="outline" className={`${statusCfg.color} gap-1.5 font-semibold text-xs mr-2`}>
          <statusCfg.icon size={11} />
          {statusCfg.label}
        </Badge>
      )}
      {schedule.status === WorkScheduleStatus.Submitted && (
        <>
          <Button size="sm" variant="destructive" onClick={() => setIsRejectOpen(true)}>
            <XCircle size={14} /> Reject
          </Button>
          <Button size="sm" onClick={() => approveMutation.mutate(schedule.id)} disabled={approveMutation.isPending}>
            <CheckCircle size={14} /> Approve
          </Button>
        </>
      )}
      {schedule.status === WorkScheduleStatus.Approved && (
        <Button size="sm" variant="outline" onClick={() => setIsUnfreezeOpen(true)}>
          Unfreeze
        </Button>
      )}
    </div>
  ) : null;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate(ROUTES.workScheduleForUser(userId))}>
          <ArrowLeft size={14} /> Back to list
        </Button>
        {!canApprove && statusCfg && (
          <Badge variant="outline" className={`${statusCfg.color} gap-1.5 font-semibold text-xs`}>
            <statusCfg.icon size={11} />
            {statusCfg.label}
          </Badge>
        )}
      </div>

      {schedule?.reviewNotes && (
        <div className="px-4 py-3 bg-amber-50 border border-amber-100 rounded-xl flex items-start gap-2">
          <AlertCircle size={14} className="text-amber-600 mt-0.5 shrink-0" />
          <p className="text-xs text-amber-800 font-medium">{schedule.reviewNotes}</p>
        </div>
      )}

      {isError ? (
        <div className="section-card p-16 flex flex-col items-center gap-3 text-muted-foreground">
          <AlertCircle size={36} className="opacity-30" />
          <p className="text-sm font-medium">No schedule found for {monthLabel}.</p>
        </div>
      ) : (
        <HarmonyFullCalendar
          schedules={schedule ? [schedule] : []}
          initialDate={new Date(year, month - 1, 1)}
          editable={false}
          isLoading={isLoading}
          toolbarActions={approvalActions}
        />
      )}

      {/* Reject modal */}
      <HarmonyDialog
        open={isRejectOpen}
        onOpenChange={(open) => { if (!open) { setIsRejectOpen(false); setRejectNotes(""); } }}
        title="Reject Schedule"
        description={monthLabel}
        size="md"
        onSubmit={() => schedule && rejectMutation.mutate({ monthId: schedule.id, notes: rejectNotes.trim() })}
        submitLabel="Confirm Reject"
        isSubmitting={rejectMutation.isPending}
        submitDisabled={!rejectNotes.trim()}
      >
        <div className="space-y-5">
          <p className="text-sm font-medium leading-relaxed">
            Please provide a reason for rejection. This note will be visible to the team member.
          </p>
          <div>
            <label htmlFor="reject-notes" className="ws-label">Review Notes <span className="text-rose-500">*</span></label>
            <textarea
              id="reject-notes"
              value={rejectNotes}
              onChange={(e) => setRejectNotes(e.target.value)}
              rows={4}
              className="w-full px-4 py-3 border border-border rounded-2xl text-sm text-foreground placeholder:text-muted-foreground font-medium focus:outline-none focus:ring-2 focus:ring-destructive/30 focus:border-destructive transition-all resize-none bg-muted/30"
            />
          </div>
          {rejectMutation.isError && (
            <div className="p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-2.5">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">{getApiErrorMessage(rejectMutation.error)}</p>
            </div>
          )}
        </div>
      </HarmonyDialog>

      {/* Unfreeze modal */}
      <HarmonyDialog
        open={isUnfreezeOpen}
        onOpenChange={(open) => { if (!open) setIsUnfreezeOpen(false); }}
        title="Unfreeze Schedule"
        description={monthLabel}
        size="md"
        onSubmit={() => schedule && unfreezeMutation.mutate(schedule.id)}
        submitLabel="Unfreeze Schedule"
        isSubmitting={unfreezeMutation.isPending}
      >
        <div className="space-y-4">
          <p className="text-sm font-medium leading-relaxed">
            This will unlock the approved schedule, allowing the employee to make changes again.
          </p>
          <div className="p-4 bg-amber-50 border border-amber-200/80 rounded-2xl flex items-start gap-3">
            <AlertTriangle className="w-3.5 h-3.5 text-amber-600 mt-0.5" />
            <p className="text-amber-800 text-sm font-medium leading-relaxed">
              The schedule status will be reset to Draft. The employee will need to resubmit for approval.
            </p>
          </div>
        </div>
      </HarmonyDialog>
    </div>
  );
}

export default function UserWorkSchedule() {
  const { userId } = useParams<{ userId: string }>();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();

  const yearParam = searchParams.get("year");
  const monthParam = searchParams.get("month");

  const isCalendarMode = !!(yearParam && monthParam);
  const { data: months = [], isLoading } = useUserWorkScheduleMonths(userId ?? "", {
    enabled: !isCalendarMode,
  });

  if (!userId) return null;

  if (yearParam && monthParam) {
    return (
      <UserScheduleCalendar
        userId={userId}
        year={parseInt(yearParam)}
        month={parseInt(monthParam)}
      />
    );
  }

  const handleRowClick = (row: WorkScheduleMonthSummary) => {
    navigate(`${ROUTES.workScheduleForUser(userId)}?year=${row.year}&month=${row.month}`);
  };

  const userName = months[0]?.userFullName ?? undefined;

  return (
    <WorkScheduleMonthList
      months={months}
      loading={isLoading}
      onRowClick={handleRowClick}
      userName={userName}
    />
  );
}
